with cte as
(
  select [NextExecuteDate], [Attempt]
  from [WorkflowQueueItem] with (rowlock, readpast)
  where [ServerConnectionUid] is null and [Id] = :id
)
update cte set [Attempt] = case
  when [Attempt] = :attemptLength then [Attempt] - 1
  else [Attempt]
end, [NextExecuteDate] = :currentTimestamp;







delete [WorkflowQueueItem] from [WorkflowQueueItem] wqi
left join [BackgroundOperationInfo] boi
on wqi.[BackgroundOperation] = boi.[Id]
where wqi.[Instance] = :instance and ([BackgroundOperation] is null or boi.[Status] = :statusPrepared);
delete from [BackgroundOperationInfo] where [Status]=:statusPrepared;
with cte as
(
  select boi.Id, boi.[Status] from [BackgroundOperationInfo] boi with(rowlock, readpast) where boi.Id in 
  (
    select [BackgroundOperation] from [WorkflowQueueItem] where [Instance] = :instance and not [BackgroundOperation] is null
  ) and boi.[Status] = :statusActive
) update cte set [Status] = :statusPending
output inserted.Id;

DECLARE @UserGroups TABLE (GroupId bigint) INSERT INTO @UserGroups (GroupId) SELECT GroupId FROM GetGroupsForUsers(:userId);
DECLARE @ProcessHeader TABLE (Id bigint primary key, Name nvarchar(max), ParentId bigint, Published bigint) INSERT INTO @ProcessHeader (Id, Name, ParentId, Published) select distinct ph.Id, ph.Name, ph.ParentGroup as ParentId, ph.Published as Published from ProcessHeader ph with (nolock) inner join RESPONSIBILITYMATRIXITEM rm with (nolock) on rm.BPMNPROCESS = ph.PUBLISHED left join ORGANIZATIONITEM dep with (nolock) on rm.workertype = :orgitemtype and dep.Id = rm.WORKERID left join OrganizationItemUsers du with (nolock) on rm.workertype = :orgitemtype and du.ORGANIZATIONITEMID = dep.ID left join @UserGroups gu on 1=1 where (ph.Published is not null) and (ph.Status = :publishedStatus) and (:filterByResponsibilityLevel = 0 or rm.ResponsibilityLevel in (:responsibilityLevel) and ( (dep.USERID = :userId or rm.WORKERTYPE = :orgitemtype and du.USERID = :userId) or (rm.workertype = :usergrouptype and gu.GroupId = rm.workerId) )) and (:filterByCurator = 0 or rm.isCurator = :isCurator and ( (dep.USERID = :userId or rm.WORKERTYPE = :orgitemtype and du.USERID = :userId) or (rm.workertype = :usergrouptype and gu.GroupId = rm.workerId) )) and (:filterByPermission = 0 or ph.Id in ( select p.ProcessHeader from ProcessHeaderPermission p inner join UserSecuritySetCache c on p.UserSecuritySetCacheId = c.SetId where c.UserId = :userId and p.PermissionId = :permissionId) )
select ph.Id as Id, ph.Name as Name, ph.ParentId, ci.CurrentInstanceCount as AvailableCount, ci.ActiveTasksCount as AssignToMeCount, ci.CompletedInstanceCount as CompleteCount, ci.TerminatedInstanceCount as InterruptedCount, wp.ShowIndicatorMode as ShowIndicatorMode, wp.ShowProblemMetric as ShowProblemMetric, wp.HasProblemMetric as HasProblemMetric, wp.ShowWarningMetric as ShowWarningMetric, wp.HasWarningMetric as HasWarningMetric, wp.ShowGoodMetric as ShowGoodMetric from @ProcessHeader ph left join MonitorCacheItem ci on ci.ProcessHeader = ph.Id and ci.[User] is null left join WorkflowProcess wp on ph.Published = wp.Id order by ph.Name

procedure.text:

CREATE procedure [EMH_WorkflowInstanceTasksUpdated]
(
	@CreationDate datetime,
	@CreationAuthor bigint,
	@ActionTypeUid uniqueidentifier,
	@Instance bigint
)
as
begin

  declare @insTable table (
	  [Id] [bigint] NOT NULL Primary KEY,
	  [CreationDate] [datetime] NULL,
	  [CreationAuthor] [bigint] NULL,
	  [ObjectTypeUid] [uniqueidentifier] NULL,
	  [ActionTypeUid] [uniqueidentifier] NULL,
	  [ObjectUid] [uniqueidentifier] NULL,
	  [ObjectId] [bigint] NULL
  );

  declare @insCounter bigint, @insStartId bigint, @insEndId bigint;

  insert into @insTable ([Id], [CreationDate], [CreationAuthor], [ActionTypeUid], [ObjectTypeUid], [ObjectUid], [ObjectId])
  select
    ROW_NUMBER() over (order by t.[Id]) - 1,
    @CreationDate, 
    @CreationAuthor, 
    @ActionTypeUid, 
    t.[TypeUid], 
    t.[Uid], 
    t.[Id]
  from [TaskBase] t
  left join [WorkflowBookmark] b on b.[Id]=t.[WorkflowBookmark]
  where b.[Instance]=@Instance

	SELECT @insCounter = COUNT(Id) FROM @insTable;

	EXECUTE [G_GenId] 'EntityModelHistory', @insCounter, @insStartId out, @insEndId out;

  insert into [EntityModelHistory] ([Id], [CreationDate], [CreationAuthor], [ActionTypeUid], [ObjectTypeUid], [ObjectUid], [ObjectId])
  select @insStartId + [Id], [CreationDate], [CreationAuthor], [ActionTypeUid], [ObjectTypeUid], [ObjectUid], [ObjectId] from @insTable

  delete from @insTable

end
